"use client";

import React, { useRef, useState } from "react";
import { cn } from "@/lib/utils";
import { Flame, Palette, CheckCircle2Icon } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";

const SpotlightCard = ({
  children,
  className,
  activeColorHex = "#3b82f6",
}: {
  children?: React.ReactNode;
  className?: string;
  activeColorHex?: string;
}) => {
  const divRef = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [opacity, setOpacity] = useState(0);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!divRef.current) return;

    const div = divRef.current;
    const rect = div.getBoundingClientRect();

    setPosition({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  const handleMouseEnter = () => setOpacity(1);
  const handleMouseLeave = () => setOpacity(0);

  const getRgba = (hex: string, alpha: number) => {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const finalSpotlightColor = getRgba(activeColorHex, 0.15);
  const finalBorderColor = getRgba(activeColorHex, 0.4);

  return (
    <div className="group/spotlight-wrap [perspective:2000px]">
      <div
        ref={divRef}
        onMouseMove={handleMouseMove}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        className={cn(
          "relative flex h-full w-full flex-col overflow-hidden rounded-2xl border bg-card p-0  transition-all duration-500 [transform-style:preserve-3d] group-hover/spotlight-wrap:shadow-2xl group-hover/spotlight-wrap:[transform:translateZ(20px)]",
          className,
        )}
      >
        {/* Dynamic Background Glow */}
        <div
          className="pointer-events-none absolute -inset-px transition-opacity duration-500"
          style={{
            opacity,
            background: `radial-gradient(600px circle at ${position.x}px ${position.y}px, ${finalSpotlightColor}, transparent 40%)`,
          }}
        />

        {/* Dynamic Border Glow */}
        <div
          className="pointer-events-none absolute -inset-px rounded-[inherit] border-2 transition-opacity duration-500"
          style={{
            opacity,
            borderColor: finalBorderColor,
            maskImage: `radial-gradient(150px circle at ${position.x}px ${position.y}px, black, transparent)`,
            WebkitMaskImage: `radial-gradient(150px circle at ${position.x}px ${position.y}px, black, transparent)`,
          }}
        />

        {/* 3D Content Layer */}
        <div className="relative z-10 size-full transition-transform duration-500 [transform:translateZ(0px)] group-hover/spotlight-wrap:[transform:translateZ(60px)] [transform-style:preserve-3d]">
          {children}
        </div>
      </div>
    </div>
  );
};

export default function SpotlightCardDemo() {
  const [activeColor, setActiveColor] = useState("blue-500");

  const colors = [
    {
      name: "Blue",
      color: "blue-500",
      hex: "#3b82f6",
    },
    {
      name: "Teal",
      color: "teal-400",
      hex: "#14b8a6",
    },
    {
      name: "Orange",
      color: "orange-400",
      hex: "#f97316",
    },
    {
      name: "Red",
      color: "red-500",
      hex: "#ef4444",
    },
  ];

  const activeOption = colors.find((c) => c.color === activeColor) || colors[0];

  const plan = {
    plan_name: "Pro Plus",
    plan_descp:
      "Scale with confidence using premium blocks, templates, and included strategy guidance.",
    plan_price: 3800,
    plan_feature: [
      "Everything in Pro",
      "Premium templates & more sections",
      "Early access to new components",
      "Private Discord & priority support",
      "Monthly strategy & growth sessions",
    ],
  };

  return (
    <div className="flex flex-col items-center gap-10 p-12 min-h-[900px] bg-background">
      {/* Theme Selection UI - Simplified */}
      <div className="flex flex-col items-center gap-4">
        <div className="flex items-center gap-2 text-xs font-semibold text-muted-foreground uppercase tracking-widest">
          <Palette className="size-4" />
          <span>Accent Color</span>
        </div>
        <div className="flex gap-3">
          {colors.map((color) => (
            <button
              key={color.name}
              onClick={() => setActiveColor(color.color)}
              className={cn(
                "size-6 rounded-full transition-all duration-300 hover:scale-105 active:scale-95",
                `bg-${color.color}`,
                activeColor === color.color
                  ? "ring-2 ring-foreground ring-offset-2 ring-offset-background scale-110"
                  : "hover:opacity-100",
              )}
              title={color.name}
            />
          ))}
        </div>
      </div>

      <div className="w-full max-w-[420px]">
        <SpotlightCard
          activeColorHex={activeOption.hex}
          className="min-h-[580px] border-0"
        >
          {/* Using same typography as Pricing-02 block */}
          <Card className="relative flex-1 flex flex-col h-full rounded-2xl p-8 gap-8 border border-border/50 bg-transparent shadow-none [transform-style:preserve-3d]">
            <CardHeader className="p-0 [transform-style:preserve-3d]">
              <div className="flex flex-col gap-3 self-stretch [transform-style:preserve-3d]">
                <div className="flex items-center justify-between [transform:translateZ(40px)]">
                  <CardTitle
                    className={cn(
                      "text-2xl font-medium",
                      `text-${activeOption.color}`,
                    )}
                  >
                    {plan.plan_name}
                  </CardTitle>
                  <Badge
                    className={cn(
                      "py-1 px-3 text-sm font-medium leading-5 w-fit h-7 flex items-center gap-1.5 [&>svg]:size-4! border-none shadow-lg shadow-black/5 transition-colors",
                      `bg-${activeOption.color}/10`,
                      `text-${activeOption.color}`,
                    )}
                  >
                    <Flame className="size-16" /> Recommend
                  </Badge>
                </div>
                <CardDescription className="text-base font-normal max-w-2x [transform:translateZ(20px)]">
                  {plan.plan_descp}
                </CardDescription>
              </div>
            </CardHeader>

            <CardContent className="flex flex-col flex-1 gap-8 p-0 [transform-style:preserve-3d]">
              <div className="flex items-baseline gap-1 [transform:translateZ(60px)]">
                <span className="text-foreground text-4xl sm:text-5xl font-medium">
                  ${plan.plan_price}
                </span>
                <span className="text-muted-foreground text-base font-normal">
                  /month
                </span>
              </div>

              <Separator orientation="horizontal" />

              <ul className="flex flex-col gap-4 flex-1 [transform:translateZ(30px)]">
                {plan.plan_feature.map((feature, idx) => (
                  <li
                    key={idx}
                    className="flex items-center gap-3 text-base font-normal text-muted-foreground"
                  >
                    <CheckCircle2Icon
                      className={cn(
                        "size-4 shrink-0 transition-colors",
                        `text-${activeOption.color}`,
                      )}
                    />
                    {feature}
                  </li>
                ))}
              </ul>

              <Button
                className={cn(
                  "w-full h-12 cursor-pointer shadow-2xl [transform:translateZ(80px)] text-white font-bold transition-all",
                  `bg-${activeOption.color} hover:bg-${activeOption.color}/90`,
                )}
              >
                Get started
              </Button>
            </CardContent>
          </Card>
        </SpotlightCard>
      </div>
    </div>
  );
}
